import React, { useContext } from "react";
import { useNavigate } from "react-router-dom";
import AuthContext from "../context/AuthContext";
import "./Home.css"; // Reuse card styles

function Subscription() {
    const { user, login } = useContext(AuthContext); // We might need to update user context
    const navigate = useNavigate();

    const handlePurchase = async () => {
        if (!user) {
            navigate("/login");
            return;
        }

        try {
            const response = await fetch("http://localhost:5001/api/subscription/purchase", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ userId: user.id || user._id }),
            });

            if (response.ok) {
                alert("Subscription Successful! You can now chat with CAs.");
                // Optionally refresh user context here if possible, or just navigate
                navigate("/");
                window.location.reload(); // Simple way to refresh context
            } else {
                alert("Subscription failed.");
            }
        } catch (error) {
            console.error("Error purchasing subscription:", error);
        }
    };

    return (
        <div className="home-container" style={{ paddingTop: "4rem", textAlign: "center" }}>
            <h1>Unlock Premium Features</h1>
            <p style={{ fontSize: "1.2rem", color: "#64748b", marginBottom: "3rem" }}>
                Subscribe to chat with unlimited Chartered Accountants.
            </p>

            <div className="ca-grid" style={{ maxWidth: "400px", margin: "0 auto" }}>
                <div className="ca-card" style={{ padding: "2rem", display: "flex", flexDirection: "column", alignItems: "center" }}>
                    <h2 style={{ color: "#2563eb", marginBottom: "1rem" }}>Pro Plan</h2>
                    <div style={{ fontSize: "2.5rem", fontWeight: "bold", marginBottom: "1rem" }}>
                        ₹499<span style={{ fontSize: "1rem", color: "#94a3b8" }}>/month</span>
                    </div>
                    <ul style={{ listStyle: "none", padding: 0, textAlign: "left", marginBottom: "2rem", color: "#475569" }}>
                        <li style={{ marginBottom: "0.5rem" }}>✅ Unlimited Chats</li>
                        <li style={{ marginBottom: "0.5rem" }}>✅ Priority Support</li>
                        <li style={{ marginBottom: "0.5rem" }}>✅ Verified CAs</li>
                    </ul>
                    <button
                        className="view-btn"
                        style={{ width: "100%", backgroundColor: "#2563eb", color: "white", padding: "1rem" }}
                        onClick={handlePurchase}
                    >
                        Buy Subscription
                    </button>
                </div>
            </div>
        </div>
    );
}

export default Subscription;
